      out.write("async function loadRoleOptions() {\n");
      out.write("    try {\n");
      out.write("        const storeId = '");
      out.print(currentStoreId);
      out.write("';\n");
      out.write("        const res  = await fetch('GetRoles?storeId=' + encodeURIComponent(storeId));\n");
      out.write("        const data = await res.json();\n");
      out.write("\n");
      out.write("        if (data.status === 'success') {\n");
      out.write("            document.querySelectorAll('.role-select').forEach(function(select) {\n");
      out.write("                const currentVal = select.dataset.current || '0';\n");
      out.write("                data.list.forEach(role => {\n");
      out.write("                    const opt = document.createElement('option');\n");
