      out.write("                    opt.text        = role.roleName;\n");
      out.write("                    opt.dataset.wage = role.wage;\n");
      out.write("                    if (String(role.roleId) === String(currentVal)) opt.selected = true;\n");
      out.write("                    select.appendChild(opt);\n");
      out.write("                });\n");
      out.write("            });\n");
      out.write("        }\n");
      out.write("    } catch (e) { console.error(e); }\n");
      out.write("}\n");
      out.write("\n");
      out.write("async function assignRole(memId, select) {\n");
      out.write("    const roleId   = select.value;\n");
      out.write("    const roleName = select.options[select.selectedIndex].text;\n");
      out.write("\n");
      out.write("    if (!confirm('\"' + roleName + '\" 역할을 지정하시겠습니까?')) {\n");
      out.write("        select.value = select.dataset.current || '0';\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    const params = new URLSearchParams();\n");
      out.write("    params.append('memId',  memId);\n");
      out.write("    params.append('roleId', roleId);\n");
      out.write("\n");
      out.write("    try {\n");
      out.write("        const res  = await fetch('RoleAssign', { method: 'POST', body: params });\n");
      out.write("        const data = await res.json();\n");
      out.write("\n");
      out.write("        if (data.status === 'success') {\n");
      out.write("            select.dataset.current = roleId;\n");
      out.write("            const wageEl = document.getElementById('wage-' + memId);\n");
      out.write("            if (wageEl) {\n");
      out.write("                wageEl.innerText = data.wage > 0 ? Number(data.wage).toLocaleString() + '원' : '-';\n");
      out.write("                const badge = document.createElement('span');\n");
      out.write("                badge.className = 'badge bg-success ms-1';\n");
      out.write("                badge.innerText = '저장됨';\n");
      out.write("                wageEl.after(badge);\n");
      out.write("                setTimeout(() => badge.remove(), 2000);\n");
      out.write("            }\n");
      out.write("        } else {\n");
      out.write("            showToast(data.message, 'danger');\n");
      out.write("            select.value = select.dataset.current || '0';\n");
