      out.write("        showToast('통신 오류가 발생했습니다.', 'danger');\n");
      out.write("        select.value = select.dataset.current || '0';\n");
      out.write("    }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function filterTable() {\n");
      out.write("    const filter = document.getElementById('searchInput').value.toUpperCase();\n");
      out.write("    const rows   = document.querySelectorAll('#memberTable tbody tr');\n");
      out.write("    rows.forEach(tr => {\n");
